const DART_SYNCBLOB: &str = r#"{"ciphertext":[122,39,131,198,23,2,34,37,87,111,138,155,133,245,206,177,127,87,201,193,17,201,156,89,40,40,17,255,180,186,43,189,123,163,155,127,233,40,141,220,46,32,152,227,67,66,75,90,53,183,120,234,254,80,43,188,119,164,10,232,77,31,35,174,210,68,245,5,75,154,198,244,107,190,135,8,200,154,180,122,36,235,154,176,149,112,23,168,58,67,112,46,90,0,158,10,227,160,223,252,126,120,218,78,197,151,138,109,148,234,13,156,177,52,211,175,122,139,55,134,80,57,197,144,239,8,186,197,170,64,105,189,13,213,126,223,49,176,58,209,198,151,220,166,114,49,121,20,60,113,80,43,64,13,113,181,91,204,122,4,94,160,113,174,254,15,8,34,249,74,255,194,137,200,5,91,29,236,139,157,193,194,145,107,206,209,40,101,109,43,45,90,110,48,191,186,31,172,251,112,129,6,131,68,65,237,22,33,160,116,184,117,113,243,83,116,218,91,224,174,240,102,46,193,238,220,196,142,132,224,248,201,230,227,187,73,168,184,151,66,192,82,10,116,201,162,35,234,243,30,55,2,64,127,145,25,49,75,44,250,151,34,131,215,54,242,158,87,71,169,18,239,106,203,190,166,222,174,15,108,197,85,206,200,40,213,247,161,9,209,157,193,184,220,53,173,123,104,253,177,23,16,191,70,104,35,117,211,236,4,29,137,203,94,240,58,242,241,223,23,194,106,118,51,189],"nonce":[246,101,192,166,214,153,223,232,112,181,112,179,50,123,92,230,88,176,7,47,245,201,215,81],"kdf_salt":[9,187,51,174,32,48,109,38,104,197,54,124,24,148,21,217],"kdf_params":{"mem_kib":8192,"iterations":1,"parallelism":1}}"#;

#[test]
fn opens_dart_sealed_vault_file() {
    let file: VaultFile = serde_json::from_str(DART_VAULTFILE).expect("parse vault json");
    let (data, _dek) = file.unlock(b"123456").expect("unlock with passcode");
    assert_eq!(data.accounts.len(), 1);
    assert_eq!(data.accounts[0].issuer, "GitHub");
    // Same secret => same RFC code the mobile app shows (t=59 -> 287082).
    assert_eq!(data.accounts[0].current_code(59).unwrap(), "287082");
}

#[test]
fn rejects_dart_vault_with_wrong_passcode() {
    let file: VaultFile = serde_json::from_str(DART_VAULTFILE).unwrap();
    assert!(file.unlock(b"999999").is_err());
}

#[test]
fn opens_dart_sealed_sync_blob() {
    let blob: SealedBlob = serde_json::from_str(DART_SYNCBLOB).expect("parse blob json");
    assert!(blob.is_well_formed());
    let data = open_downloaded(&blob, b"account-pw").expect("open downloaded");
    assert_eq!(data.accounts.len(), 1);
    assert_eq!(data.accounts[0].issuer, "GitHub");
}
